<template>
	<view class="container">
		<view class="banner">
			<text class="banner-title">女神新宠岂止于好</text>
			<text class="banner-description">瑜伽课程包</text>
			<view class="banner-activity">立即开抢 ></view>
		</view>
		<view class="service">
			<view class="service-item" v-for="item in services">
				<image :src="item.imgSrc"></image>
				<view>{{item.text}}</view>
			</view>
		</view>
		<view class="shop">
			<!-- <view class="shop-top">
				<view class="shop-top-buy" :class="TopClassActive" @click="changeNav('buy')">购买</view>
				<view class="shop-top-comment" :class="TopClassDisActive" @click="changeNav('comment')">评价</view>
				<view style="flex:3"></view>
			</view> -->
			<view>

			</view>
			<view class="shop-content">
				<view class="shop-content-nav">
					<view class="shop-content-nav-item" :class="asideClassActive" v-for="item in categoryList"
						@click="initShop(item.id)">
						{{item.name}}
					</view>
				</view>
				<view class="shop-content-shop">
					<view v-if="shopList!=null">
						<view class="shop-content-shop-item" v-for="item in shopList" @click="shopDetail(item)" >
							<view class="shop-content-shop-item-image">
								<image :src="item.image"></image>
							</view>
							<view class="shop-content-shop-item-right">
								<view class="shop-content-shop-item-shopName">
									{{item.shopName}}
								</view>
								<view class="shop-content-shop-item-description">
									{{item.description}}
								</view>
								<view class="shop-content-shop-item-price">
									<view class="shop-content-shop-item-oldPrice">
										<view v-if="item.oldPrice!=null">
											{{item.oldPrice}}¥
										</view>
										<view v-else class="shop-content-shop-item-oldPrice">
											最新价
										</view>
									</view>
									<view class="shop-content-shop-item-newPrice">
										{{item.newPrice}}¥
										<view v-if="item.status==1" class="shop-content-shop-item-buy">
											购买
										</view>
										<view v-else class="shop-content-shop-item-disBuyed">
											停售
										</view>
									</view>
								</view>
							</view>
						</view>
					</view>
				</view>
				
			</view>
		</view>
	</view>
</template>

<script>
	import {
		getCardList
	} from '../../api/card'
	import {
		getCategoryList
	} from '../../api/category'
	import {
		getShopByCategoryId,
	} from '../../api/shop'
	import {
		baseUrl
	} from '../../config'
	export default {
		data() {
			return {
				services: [{
					imgSrc: "/static/img2/cardApplication.png",
					text: "办卡",
					url: "/cardApplication"
				}, {
					imgSrc: "/static/img2/coursePackage.png",
					text: "课程包",
					url: "/cardApplication"
				}, {
					imgSrc: "/static/img2/commodity.png",
					text: "商品",
					url: "/cardApplication"
				}, {
					imgSrc: "/static/img2/exchange.png",
					text: "积分兑换",
					url: "/cardApplication"
				}],
				categoryList: [],
				shopList: [],
				TopClassActive: "topClassActive",
				TopClassDisActive: "topClassDisActive",

			}

		},
		methods: {
			changeNav(val) {
				if (val == 'buy') {
					this.TopClassActive = 'topClassActive'
					this.TopClassDisActive = 'topClassDisActive'
				} else {
					this.TopClassActive = "topClassDisActive"
					this.TopClassDisActive = 'topClassActive'
				}
			},
			initShop(categoryId) {
				getShopByCategoryId(categoryId).then(res => {
					console.log(res);
					this.shopList = res.data.data
					for (var i = 0; i < res.data.data.length; i++) {
						res.data.data[i].image=baseUrl+"/common/download?name="+res.data.data[i].image
					}
					if(res.data.data.length==0){
						uni.showToast({
							title:"暂无更多商品",
							duration:2000,
							icon:"error"
						})
					}
				})
			},
			shopDetail(item){
				if(item.status==0){
					uni.showToast({
						title:"商品已停售",
						icon:"error"
					})
				}else{
					uni.navigateTo({
					url:"/pages/detail/shopDetail?id="+item.id
				})
				}
				
			}
		},
		onLoad() {
			getCategoryList().then(res => {
				console.log(res);
				this.categoryList = res.data.data
				this.initShop(res.data.data[0].id)
			})


		}
	}
</script>

<style>
