		white-space: nowrap;
		overflow: hidden;
		text-overflow: ellipsis;

	}

	.banner {
		background-image: url(/static/img2/banner.jpg);
		width: 100%;
		background-size: 100%;
		height: 34vh;
		background-repeat: no-repeat;
		background-color: red;
		position: relative;
		z-index: 1;
		white-space: nowrap;
