		text-shadow: 2px 0 white, -2px 0 white, 0 2px white, 0 -2px white, 1.4px 1.4px white, 1.4px -1.4px white, -1.4px 1.4px white, -1.4px -1.4px white;
	}

	.banner-description {
		position: absolute;
		top: 14vh;
		right: 12vh;
		color: #000;
		font-weight: bold;
		text-shadow: 2px 0 white, -2px 0 white, 0 2px white, 0 -2px white, 1.4px 1.4px white, 1.4px -1.4px white, -1.4px 1.4px white, -1.4px -1.4px white;
		white-space: nowrap;
		overflow: hidden;

	}

	.banner-activity {
		position: absolute;
		border-radius: 2vh;
		width: 12vh;
		text-align: center;
		background-color: #F83448;
		color: white;
		padding: 0.4vh;
		top: 19vh;
		right: 11vh;

	}

	.service {
		width: 90%;
		display: flex;
		justify-content: space-around;
		background-color: #FFFFFF;
		z-index: 2;
		position: absolute;
		height: 10vh;

		top: 30%;
		border-radius: 2vh;
		padding-top: 2vh;

	}

	.service-item {
		text-align: center;

	}

	.service-item image {
		width: 6vh;
		height: 6vh;
	}

	.hot {
		display: flex;
		position: absolute;
		width: 90%;
		top: 45%;
		background-color: white;
		justify-content: center;
		height: 25%;
		border-radius: 2vh;
	}

	.hot-banner {
		display: flex;
		/* justify-content: space-between; */
		position: absolute;
		top: 1.5vh;
		height: 5vh;
		width: 90%;
	}

	.hot-title {
		position: absolute;
		left: vh;
		font-weight: bold;
	}

	.hot-more {
		position: absolute;
		right: 0.5vh;
	}

	.hot-item {
		height: 20vh;
		background-color: red;
		z-index: 2;
		white-space: nowrap;
		width: 100%;
	}

	.hot-card {
		width: 90%;
		height: 10vh;
		position: absolute;
		top: 6vh;
	}

	.hot-card-item image {
		display: flex;
