		text-shadow: 2px 0 white, -2px 0 white, 0 2px white, 0 -2px white, 1.4px 1.4px white, 1.4px -1.4px white, -1.4px 1.4px white, -1.4px -1.4px white;
		white-space: nowrap;
		overflow: hidden;
	}

	.shop-top-buy {
		flex: 1;
