	}

	.shop-content {
		display: flex;
		flex: 1;
	}

	.shop-content-nav {
		font-size: 2vh;
		text-align: center;
		flex: 0 0 10vh;
	}

	.shop-content-nav-item {
		height: 6vh;
		line-height: 6vh;
	}

	.shop-content-shop {
		flex: 1;


	}

	.shop-content-shop-item {

		/* background-color: antiquewhite; */
		display: flex;
		margin-bottom: 2vh;
		margin: 4vh auto;
		border-radius: 2vh;
	}

	.shop-content-shop-item-right {
		flex: 3;
