		color: darkgray;
		font-weight: bold;
		color: red;
	}

	.shop-content-shop-item-newPrice {
		font-size: 2.5vh;
		color: orangered;
		display: flex;
		

	}

	.shop-content-shop-item-buy {
		flex: 2;
		margin-left: 2vh;
		text-align: right;
		
	}
	.shop-content-shop-item-disBuyed{
		flex: 2;
		margin-left: 2vh;
